using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

/// <summary>
/// Shared test helpers for creating in-memory DbContext and seeding data.
/// </summary>
internal static class TestHelpers
{
    /// <summary>
    /// Creates a fresh SchoolContext backed by an in-memory database with a unique name.
    /// </summary>
    public static SchoolContext CreateInMemoryContext()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
            .Options;

        var context = new SchoolContext(options);
        context.Database.EnsureCreated();
        return context;
    }

    /// <summary>
    /// Seeds a context with sample students.
    /// </summary>
    public static void SeedStudents(SchoolContext context, int count = 3)
    {
        for (int i = 1; i <= count; i++)
        {
            context.Students.Add(new Student
            {
                LastName = $"Student{i}",
                FirstMidName = $"First{i}",
                EnrollmentDate = new DateTime(2020, 1, i)
            });
        }
        context.SaveChanges();
    }

    /// <summary>
    /// Seeds a context with a department and instructor.
    /// </summary>
    public static (Department department, Instructor instructor) SeedDepartmentWithInstructor(SchoolContext context)
    {
        var instructor = new Instructor
        {
            LastName = "TestInstructor",
            FirstMidName = "John",
            HireDate = new DateTime(2010, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var department = new Department
        {
            Name = "Engineering",
            Budget = 100000m,
            StartDate = new DateTime(2015, 9, 1),
            InstructorID = instructor.ID
        };
        context.Departments.Add(department);
        context.SaveChanges();

        return (department, instructor);
    }

    /// <summary>
    /// Seeds a context with a course in a department.
    /// </summary>
    public static Course SeedCourse(SchoolContext context, int courseId = 1050)
    {
        var department = new Department
        {
            Name = "TestDept",
            Budget = 50000m,
            StartDate = new DateTime(2015, 1, 1)
        };
        context.Departments.Add(department);
        context.SaveChanges();

        var course = new Course
        {
            CourseID = courseId,
            Title = "Test Course",
            Credits = 3,
            DepartmentID = department.DepartmentID
        };
        context.Courses.Add(course);
        context.SaveChanges();

        return course;
    }
}

