using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class ModelsTests
{
    #region Person.FullName Tests

    [TestMethod]
    public void FullName_WithLastAndFirstName_ReturnsFormattedName()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = "John",
            EnrollmentDate = DateTime.Today
        };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual("Smith, John", result);
    }

    [TestMethod]
    public void FullName_WithDifferentNames_ReturnsFormattedName()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "O'Brien",
            FirstMidName = "Mary Jane",
            HireDate = DateTime.Today
        };

        // Act
        var result = instructor.FullName;

        // Assert
        Assert.AreEqual("O'Brien, Mary Jane", result);
    }

    [TestMethod]
    public void FullName_WithEmptyFirstName_ReturnsLastNameCommaSpace()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = "",
            EnrollmentDate = DateTime.Today
        };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual("Smith, ", result);
    }

    #endregion

    #region ErrorViewModel Tests

    [TestMethod]
    public void ShowRequestId_WhenRequestIdIsSet_ReturnsTrue()
    {
        // Arrange
        var model = new ErrorViewModel { RequestId = "abc-123" };

        // Act
        var result = model.ShowRequestId;

        // Assert
        Assert.IsTrue(result);
    }

    [TestMethod]
    public void ShowRequestId_WhenRequestIdIsNull_ReturnsFalse()
    {
        // Arrange
        var model = new ErrorViewModel { RequestId = null };

        // Act
        var result = model.ShowRequestId;

        // Assert
        Assert.IsFalse(result);
    }

    [TestMethod]
    public void ShowRequestId_WhenRequestIdIsEmpty_ReturnsFalse()
    {
        // Arrange
        var model = new ErrorViewModel { RequestId = "" };

        // Act
        var result = model.ShowRequestId;

        // Assert
        Assert.IsFalse(result);
    }

    #endregion

    #region Student Model Tests

    [TestMethod]
    public void Student_InheritsFromPerson_HasCorrectProperties()
    {
        // Arrange & Act
        var student = new Student
        {
            ID = 1,
            LastName = "Doe",
            FirstMidName = "Jane",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Assert
        Assert.AreEqual(1, student.ID);
        Assert.AreEqual("Doe", student.LastName);
        Assert.AreEqual("Jane", student.FirstMidName);
        Assert.AreEqual(new DateTime(2023, 9, 1), student.EnrollmentDate);
    }

    #endregion

    #region Instructor Model Tests

    [TestMethod]
    public void Instructor_InheritsFromPerson_HasCorrectProperties()
    {
        // Arrange & Act
        var instructor = new Instructor
        {
            ID = 5,
            LastName = "Professor",
            FirstMidName = "Test",
            HireDate = new DateTime(2015, 1, 15)
        };

        // Assert
        Assert.AreEqual(5, instructor.ID);
        Assert.AreEqual("Professor", instructor.LastName);
        Assert.AreEqual("Test", instructor.FirstMidName);
        Assert.AreEqual(new DateTime(2015, 1, 15), instructor.HireDate);
        Assert.AreEqual("Professor, Test", instructor.FullName);
    }

    #endregion

    #region Course Model Tests

    [TestMethod]
    public void Course_Properties_SetCorrectly()
    {
        // Arrange & Act
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1
        };

        // Assert
        Assert.AreEqual(1050, course.CourseID);
        Assert.AreEqual("Chemistry", course.Title);
        Assert.AreEqual(3, course.Credits);
        Assert.AreEqual(1, course.DepartmentID);
    }

    #endregion

    #region Department Model Tests

    [TestMethod]
    public void Department_Properties_SetCorrectly()
    {
        // Arrange & Act
        var department = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 200000m,
            StartDate = new DateTime(2020, 9, 1),
            InstructorID = 5
        };

        // Assert
        Assert.AreEqual(1, department.DepartmentID);
        Assert.AreEqual("Engineering", department.Name);
        Assert.AreEqual(200000m, department.Budget);
        Assert.AreEqual(new DateTime(2020, 9, 1), department.StartDate);
        Assert.AreEqual(5, department.InstructorID);
    }

    [TestMethod]
    public void Department_InstructorID_CanBeNull()
    {
        // Arrange & Act
        var department = new Department
        {
            Name = "Unassigned",
            Budget = 100000m,
            StartDate = DateTime.Today,
            InstructorID = null
        };

        // Assert
        Assert.IsNull(department.InstructorID);
    }

    #endregion

    #region Notification Model Tests

    [TestMethod]
    public void Notification_Properties_SetCorrectly()
    {
        // Arrange
        var now = DateTime.Now;

        // Act
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Student",
            EntityId = "42",
            Operation = "CREATE",
            Message = "New Student created",
            CreatedAt = now,
            CreatedBy = "Admin",
            IsRead = false,
            ReadAt = null
        };

        // Assert
        Assert.AreEqual(1, notification.Id);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("New Student created", notification.Message);
        Assert.AreEqual(now, notification.CreatedAt);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsNull(notification.ReadAt);
    }

    #endregion

    #region Enrollment Model Tests

    [TestMethod]
    [DataRow(Grade.A, DisplayName = "Grade A")]
    [DataRow(Grade.B, DisplayName = "Grade B")]
    [DataRow(Grade.C, DisplayName = "Grade C")]
    [DataRow(Grade.D, DisplayName = "Grade D")]
    [DataRow(Grade.F, DisplayName = "Grade F")]
    public void Enrollment_Grade_AcceptsAllValues(Grade grade)
    {
        // Arrange & Act
        var enrollment = new Enrollment
        {
            EnrollmentID = 1,
            CourseID = 100,
            StudentID = 1,
            Grade = grade
        };

        // Assert
        Assert.AreEqual(grade, enrollment.Grade);
    }

    [TestMethod]
    public void Enrollment_Grade_CanBeNull()
    {
        // Arrange & Act
        var enrollment = new Enrollment
        {
            EnrollmentID = 1,
            CourseID = 100,
            StudentID = 1,
            Grade = null
        };

        // Assert
        Assert.IsNull(enrollment.Grade);
    }

    #endregion
}

