using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        // Drain static queue before each test to avoid cross-test contamination
        _sut = new NotificationService();
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut?.Dispose();
    }

    #region SendNotification Tests

    [TestMethod]
    public void SendNotification_WithAllParameters_EnqueuesNotification()
    {
        // Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Course", "100", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithNullUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Course", "100", "Math", EntityOperation.UPDATE, null);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesOverload()
    {
        // Act
        _sut.SendNotification("Department", "5", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Department", notification.EntityType);
        Assert.AreEqual("5", notification.EntityId);
        Assert.AreEqual("DELETE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToNow()
    {
        // Arrange
        var before = DateTime.Now;

        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var after = DateTime.Now;
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
    }

    #endregion

    #region GenerateMessage Tests (via SendNotification)

    [TestMethod]
    public void SendNotification_CreateWithDisplayName_GeneratesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("New Student 'John Doe' has been created", notification!.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateWithDisplayName_GeneratesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Course", "100", "Math 101", EntityOperation.UPDATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("Course 'Math 101' has been updated", notification!.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteWithDisplayName_GeneratesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("Department 'Engineering' has been deleted", notification!.Message);
    }

    [TestMethod]
    public void SendNotification_CreateWithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Student", "42", null, EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("New Student (ID: 42) has been created", notification!.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateWithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Course", "100", null, EntityOperation.UPDATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("Course (ID: 100) has been updated", notification!.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteWithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Department", "5", null, EntityOperation.DELETE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("Department (ID: 5) has been deleted", notification!.Message);
    }

    [TestMethod]
    public void SendNotification_WithEmptyDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Student", "10", "", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("New Student (ID: 10) has been created", notification!.Message);
    }

    [TestMethod]
    public void SendNotification_WithWhitespaceDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Student", "10", "   ", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("New Student (ID: 10) has been created", notification!.Message);
    }

    #endregion

    #region ReceiveNotification Tests

    [TestMethod]
    public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_ReturnsInFifoOrder()
    {
        // Arrange
        _sut.SendNotification("First", "1", EntityOperation.CREATE);
        _sut.SendNotification("Second", "2", EntityOperation.UPDATE);
        _sut.SendNotification("Third", "3", EntityOperation.DELETE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.AreEqual("First", first!.EntityType);

        var second = _sut.ReceiveNotification();
        Assert.AreEqual("Second", second!.EntityType);

        var third = _sut.ReceiveNotification();
        Assert.AreEqual("Third", third!.EntityType);
    }

    [TestMethod]
    public void ReceiveNotification_RemovesFromQueue()
    {
        // Arrange
        _sut.SendNotification("Test", "1", EntityOperation.CREATE);

        // Act
        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(first);
        Assert.IsNull(second);
    }

    #endregion

    #region MarkAsRead Tests

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert (no-op but should not throw)
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(0);
        _sut.MarkAsRead(-1);
    }

    #endregion

    #region Queue Cap Tests

    [TestMethod]
    public void SendNotification_ExceedingQueueCap_TrimsOldEntries()
    {
        // Arrange - send more than 500 notifications
        for (int i = 0; i < 510; i++)
        {
            _sut.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }

        // Act - count remaining items
        int count = 0;
        while (_sut.ReceiveNotification() != null)
        {
            count++;
        }

        // Assert - queue should be capped at or near 500
        Assert.IsTrue(count <= 500, $"Queue should be capped at 500 but had {count} items");
    }

    #endregion

    #region Dispose Tests

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var service = new NotificationService();
        service.Dispose();
        // Can still use static queue after dispose since it's a no-op
    }

    #endregion
}

