using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    #region Index Tests

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithStudents()
    {
        // Arrange
        TestHelpers.SeedStudents(_context, 3);

        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
    }

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAsc()
    {
        // Arrange
        _context.Students.Add(new Student { LastName = "Zulu", FirstMidName = "A", EnrollmentDate = DateTime.Today });
        _context.Students.Add(new Student { LastName = "Alpha", FirstMidName = "B", EnrollmentDate = DateTime.Today });
        _context.Students.Add(new Student { LastName = "Middle", FirstMidName = "C", EnrollmentDate = DateTime.Today });
        _context.SaveChanges();

        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual("Alpha", model![0].LastName);
        Assert.AreEqual("Middle", model[1].LastName);
        Assert.AreEqual("Zulu", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDesc()
    {
        // Arrange
        _context.Students.Add(new Student { LastName = "Alpha", FirstMidName = "A", EnrollmentDate = DateTime.Today });
        _context.Students.Add(new Student { LastName = "Zulu", FirstMidName = "B", EnrollmentDate = DateTime.Today });
        _context.SaveChanges();

        // Act
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual("Zulu", model![0].LastName);
        Assert.AreEqual("Alpha", model[1].LastName);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAsc()
    {
        // Arrange
        _context.Students.Add(new Student { LastName = "Later", FirstMidName = "A", EnrollmentDate = new DateTime(2023, 6, 1) });
        _context.Students.Add(new Student { LastName = "Earlier", FirstMidName = "B", EnrollmentDate = new DateTime(2020, 1, 1) });
        _context.SaveChanges();

        // Act
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual("Earlier", model![0].LastName);
        Assert.AreEqual("Later", model[1].LastName);
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDesc()
    {
        // Arrange
        _context.Students.Add(new Student { LastName = "Earlier", FirstMidName = "A", EnrollmentDate = new DateTime(2020, 1, 1) });
        _context.Students.Add(new Student { LastName = "Later", FirstMidName = "B", EnrollmentDate = new DateTime(2023, 6, 1) });
        _context.SaveChanges();

        // Act
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual("Later", model![0].LastName);
        Assert.AreEqual("Earlier", model[1].LastName);
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersResults()
    {
        // Arrange
        _context.Students.Add(new Student { LastName = "Smith", FirstMidName = "John", EnrollmentDate = DateTime.Today });
        _context.Students.Add(new Student { LastName = "Jones", FirstMidName = "Mary", EnrollmentDate = DateTime.Today });
        _context.SaveChanges();

        // Act
        var result = _controller.Index(null, null, "Smith", null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model!.Count);
        Assert.AreEqual("Smith", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersResults()
    {
        // Arrange
        _context.Students.Add(new Student { LastName = "Smith", FirstMidName = "John", EnrollmentDate = DateTime.Today });
        _context.Students.Add(new Student { LastName = "Jones", FirstMidName = "Mary", EnrollmentDate = DateTime.Today });
        _context.SaveChanges();

        // Act
        var result = _controller.Index(null, null, "Mary", null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model!.Count);
        Assert.AreEqual("Jones", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchStringResetsPage()
    {
        // Arrange
        TestHelpers.SeedStudents(_context, 3);

        // Act
        var result = _controller.Index(null, null, "Student", 5) as ViewResult;

        // Assert - when searchString is not null, page resets to 1
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model!.PageIndex);
    }

    [TestMethod]
    public void Index_NullSearchStringUsesCurrentFilter()
    {
        // Arrange
        _context.Students.Add(new Student { LastName = "FilterMatch", FirstMidName = "Test", EnrollmentDate = DateTime.Today });
        _context.Students.Add(new Student { LastName = "Other", FirstMidName = "Person", EnrollmentDate = DateTime.Today });
        _context.SaveChanges();

        // Act
        var result = _controller.Index(null, "FilterMatch", null, null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model!.Count);
        Assert.AreEqual("FilterMatch", model[0].LastName);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParms()
    {
        // Arrange
        TestHelpers.SeedStudents(_context);

        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_WithNameDescSort_FlipsNameSortParm()
    {
        // Arrange
        TestHelpers.SeedStudents(_context);

        // Act
        _controller.Index("name_desc", null, null, null);

        // Assert
        Assert.AreEqual("", _controller.ViewBag.NameSortParm);
    }

    [TestMethod]
    public void Index_WithDateSort_FlipsDateSortParm()
    {
        // Arrange
        TestHelpers.SeedStudents(_context);

        // Act
        _controller.Index("Date", null, null, null);

        // Assert
        Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_Pagination_RespectsPageSize()
    {
        // Arrange - add more than 10 students (page size is 10)
        for (int i = 0; i < 15; i++)
        {
            _context.Students.Add(new Student { LastName = $"S{i:D2}", FirstMidName = "F", EnrollmentDate = DateTime.Today });
        }
        _context.SaveChanges();

        // Act
        var result = _controller.Index(null, null, null, 1) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual(10, model!.Count);
        Assert.IsTrue(model.HasNextPage);
    }

    #endregion

    #region Details Tests

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = DateTime.Today,
            Enrollments = new List<Enrollment>()
        };
        _context.Students.Add(student);
        _context.SaveChanges();

        // Act
        var result = _controller.Details(student.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.AreEqual("Test", model!.LastName);
    }

    #endregion

    #region Create Tests

    [TestMethod]
    public void Create_Get_ReturnsViewWithDefaultDate()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    [TestMethod]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = new Student
        {
            LastName = "NewStudent",
            FirstMidName = "First",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Act
        var result = _controller.Create(student) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Create_Post_ValidStudent_SavesStudentToDb()
    {
        // Arrange
        var student = new Student
        {
            LastName = "SavedStudent",
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Act
        _controller.Create(student);

        // Assert
        var saved = _context.Students.FirstOrDefault(s => s.LastName == "SavedStudent");
        Assert.IsNotNull(saved);
        Assert.AreEqual("Test", saved.FirstMidName);
    }

    [TestMethod]
    public void Create_Post_MinDateEnrollment_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsFalse(_controller.ModelState.IsValid);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_DateBefore1753_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

