    {
        // Arrange
        var dept = new Department { Name = "Math", Budget = 50000m, StartDate = DateTime.Today };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        _context.Courses.Add(new Course { CourseID = 101, Title = "Calculus", Credits = 3, DepartmentID = dept.DepartmentID });
        _context.SaveChanges();

        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Calculus", model[0].Title);
    }

    [TestMethod]
    public void Index_EmptyDatabase_ReturnsEmptyList()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        var model = result!.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    #endregion

    #region Details Tests

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
