        Assert.IsNull(_context.Courses.Find(601));
    }

    [TestMethod]
    public void DeleteConfirmed_WithImagePath_DeletesFileAndCourse()
    {
        // Arrange
        var dept = new Department { Name = "Test", Budget = 50000m, StartDate = DateTime.Today };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course
        {
