using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context = null!;
    private DepartmentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new DepartmentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    #region Index Tests

    [TestMethod]
    public void Index_ReturnsViewWithDepartments()
    {
        // Arrange
        _context.Departments.Add(new Department { Name = "Science", Budget = 100000m, StartDate = DateTime.Today });
        _context.Departments.Add(new Department { Name = "Math", Budget = 75000m, StartDate = DateTime.Today });
        _context.SaveChanges();

        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    [TestMethod]
    public void Index_EmptyDatabase_ReturnsEmptyList()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        var model = result!.Model as List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    #endregion

    #region Details Tests

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(9999);

        // Assert
        Assert.IsInstanceOfType(result, typeof(NotFoundResult));
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        // Arrange
        var dept = new Department { Name = "Engineering", Budget = 200000m, StartDate = new DateTime(2020, 1, 1) };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        // Act
        var result = _controller.Details(dept.DepartmentID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.AreEqual("Engineering", model!.Name);
        Assert.AreEqual(200000m, model.Budget);
    }

    #endregion

    #region Create Tests

    [TestMethod]
    public void Create_Get_ReturnsViewWithInstructorList()
    {
        // Arrange
        _context.Instructors.Add(new Instructor
        {
            LastName = "Smith",
            FirstMidName = "John",
            HireDate = DateTime.Today,
            CourseAssignments = new List<CourseAssignment>()
        });
        _context.SaveChanges();

        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(_controller.ViewBag.InstructorID);
