using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context = null!;
    private DepartmentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new DepartmentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    #region Index Tests

    [TestMethod]
    public void Index_ReturnsViewWithDepartments()
    {
        // Arrange
        _context.Departments.Add(new Department { Name = "Science", Budget = 100000m, StartDate = DateTime.Today });
        _context.Departments.Add(new Department { Name = "Math", Budget = 75000m, StartDate = DateTime.Today });
        _context.SaveChanges();

        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    [TestMethod]
    public void Index_EmptyDatabase_ReturnsEmptyList()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        var model = result!.Model as List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    #endregion

    #region Details Tests

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(9999);

        // Assert
        Assert.IsInstanceOfType(result, typeof(NotFoundResult));
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        // Arrange
        var dept = new Department { Name = "Engineering", Budget = 200000m, StartDate = new DateTime(2020, 1, 1) };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        // Act
        var result = _controller.Details(dept.DepartmentID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.AreEqual("Engineering", model!.Name);
        Assert.AreEqual(200000m, model.Budget);
    }

    #endregion

    #region Create Tests

    [TestMethod]
    public void Create_Get_ReturnsViewWithInstructorList()
    {
        // Arrange
        _context.Instructors.Add(new Instructor
        {
            LastName = "Smith",
            FirstMidName = "John",
            HireDate = DateTime.Today,
            CourseAssignments = new List<CourseAssignment>()
        });
        _context.SaveChanges();

        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(_controller.ViewBag.InstructorID);
    }

    [TestMethod]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        // Arrange
        var department = new Department
        {
            Name = "New Dept",
            Budget = 150000m,
            StartDate = new DateTime(2023, 1, 1)
        };

        // Act
        var result = _controller.Create(department) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Create_Post_ValidDepartment_SavesToDB()
    {
        // Arrange
        var department = new Department
        {
            Name = "Saved Dept",
            Budget = 75000m,
            StartDate = new DateTime(2023, 6, 1)
        };

        // Act
        _controller.Create(department);

        // Assert
        var saved = _context.Departments.FirstOrDefault(d => d.Name == "Saved Dept");
        Assert.IsNotNull(saved);
        Assert.AreEqual(75000m, saved.Budget);
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("Name", "Required");
        var department = new Department { Name = "", Budget = 100000m, StartDate = DateTime.Today };

        // Act
        var result = _controller.Create(department) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    #endregion

    #region Edit Tests

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null);

        // Assert
        Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(9999);

        // Assert
        Assert.IsInstanceOfType(result, typeof(NotFoundResult));
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithDepartment()
    {
        // Arrange
        var dept = new Department { Name = "EditMe", Budget = 100000m, StartDate = DateTime.Today };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        // Act
        var result = _controller.Edit(dept.DepartmentID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.AreEqual("EditMe", model!.Name);
    }

    [TestMethod]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        // Arrange
        var dept = new Department { Name = "Original", Budget = 100000m, StartDate = DateTime.Today };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updatedDept = new Department
        {
            DepartmentID = dept.DepartmentID,
            Name = "Updated",
            Budget = 200000m,
            StartDate = DateTime.Today
        };

        // Act
        var result = _controller.Edit(updatedDept) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("Name", "Required");
        var department = new Department
        {
            DepartmentID = 1,
            Name = "",
            Budget = 100000m,
            StartDate = DateTime.Today
        };

        // Act
        var result = _controller.Edit(department) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    #endregion

    #region Delete Tests

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(9999);

        // Assert
        Assert.IsInstanceOfType(result, typeof(NotFoundResult));
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithDepartment()
    {
        // Arrange
        var dept = new Department { Name = "ToDelete", Budget = 50000m, StartDate = DateTime.Today };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        // Act
        var result = _controller.Delete(dept.DepartmentID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.AreEqual("ToDelete", model!.Name);
    }

    [TestMethod]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        // Arrange
        var dept = new Department { Name = "Removing", Budget = 50000m, StartDate = DateTime.Today };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        // Act
        var result = _controller.DeleteConfirmed(dept.DepartmentID) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.IsNull(_context.Departments.Find(dept.DepartmentID));
    }

    #endregion
}

