using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context = null!;
    private InstructorsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new InstructorsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    #region Index Tests

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithInstructors()
    {
        // Arrange
        _context.Instructors.Add(new Instructor
        {
            LastName = "Smith",
            FirstMidName = "John",
            HireDate = new DateTime(2015, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        });
        _context.SaveChanges();

        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorId_LoadsCourses()
    {
        // Arrange
        var dept = new Department { Name = "CS", Budget = 100000m, StartDate = DateTime.Today };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course { CourseID = 101, Title = "Intro CS", Credits = 3, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var instructor = new Instructor
        {
            LastName = "Professor",
            FirstMidName = "Test",
            HireDate = new DateTime(2010, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        _context.CourseAssignments.Add(new CourseAssignment { CourseID = 101, InstructorID = instructor.ID });
        _context.SaveChanges();

        // Act
        var result = _controller.Index(instructor.ID, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model?.Courses);
        Assert.AreEqual(1, model.Courses.Count());
    }

    [TestMethod]
    public void Index_OrdersByLastName()
    {
        // Arrange
        _context.Instructors.Add(new Instructor { LastName = "Zulu", FirstMidName = "A", HireDate = DateTime.Today, CourseAssignments = new List<CourseAssignment>() });
        _context.Instructors.Add(new Instructor { LastName = "Alpha", FirstMidName = "B", HireDate = DateTime.Today, CourseAssignments = new List<CourseAssignment>() });
        _context.SaveChanges();

        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        var model = result!.Model as InstructorIndexData;
        var instructors = model!.Instructors.ToList();
        Assert.AreEqual("Alpha", instructors[0].LastName);
        Assert.AreEqual("Zulu", instructors[1].LastName);
    }

    #endregion

    #region Details Tests

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(9999);

        // Assert
        Assert.IsInstanceOfType(result, typeof(NotFoundResult));
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "Detail",
            FirstMidName = "Test",
            HireDate = new DateTime(2020, 6, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        // Act
        var result = _controller.Details(instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.AreEqual("Detail", model!.LastName);
    }

    #endregion

    #region Create Tests

    [TestMethod]
    public void Create_Get_ReturnsViewWithEmptyInstructor()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.CourseAssignments);
    }

    [TestMethod]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Created",
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = _controller.Create(instructor, null!) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Create_Post_WithSelectedCourses_AssignsCourses()
    {
        // Arrange
        var dept = new Department { Name = "CS", Budget = 100000m, StartDate = DateTime.Today };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course { CourseID = 700, Title = "Advanced", Credits = 4, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var instructor = new Instructor
        {
            LastName = "WithCourses",
            FirstMidName = "Test",
            HireDate = DateTime.Today,
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        _controller.Create(instructor, new[] { "700" });

        // Assert
        var saved = _context.Instructors.FirstOrDefault(i => i.LastName == "WithCourses");
        Assert.IsNotNull(saved);
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            LastName = "",
            FirstMidName = "Test",
            HireDate = DateTime.Today,
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = _controller.Create(instructor, null!) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    #endregion

    #region Edit GET Tests

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null);

        // Assert
        Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        var instructor = new Instructor
