using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context = null!;
    private NotificationsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new NotificationsController(_context);
        // Drain any existing notifications from static queue
        var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    #region GetNotifications Tests

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithZeroCount()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        // Use dynamic to read anonymous type properties
        var json = System.Text.Json.JsonSerializer.Serialize(value);
        Assert.IsTrue(json.Contains("\"success\":true"));
        Assert.IsTrue(json.Contains("\"count\":0"));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange - send notifications via the static queue
        var service = new NotificationService();
        service.SendNotification("Student", "1", "John", EntityOperation.CREATE, "Admin");
        service.SendNotification("Course", "100", "Math", EntityOperation.UPDATE, "Admin");

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var json = System.Text.Json.JsonSerializer.Serialize(result.Value);
        Assert.IsTrue(json.Contains("\"success\":true"));
        Assert.IsTrue(json.Contains("\"count\":2"));
    }

    [TestMethod]
    public void GetNotifications_LimitsToTen()
    {
        // Arrange - send more than 10 notifications
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var json = System.Text.Json.JsonSerializer.Serialize(result.Value);
        Assert.IsTrue(json.Contains("\"count\":10"));
    }

    [TestMethod]
    public void GetNotifications_ConsumesFromQueue()
    {
        // Arrange
        var service = new NotificationService();
        service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Act - first call consumes the notification
        _controller.GetNotifications();

        // Second call should be empty
        var result2 = _controller.GetNotifications();
        var json = System.Text.Json.JsonSerializer.Serialize(result2.Value);

        // Assert
        Assert.IsTrue(json.Contains("\"count\":0"));
    }

    #endregion

    #region MarkAsRead Tests

    [TestMethod]
    public void MarkAsRead_ValidId_ReturnsSuccess()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        var json = System.Text.Json.JsonSerializer.Serialize(result.Value);
        Assert.IsTrue(json.Contains("\"success\":true"));
    }

    [TestMethod]
    public void MarkAsRead_AnyId_ReturnsSuccess()
    {
        // Act - MarkAsRead is a no-op, should always succeed
        var result = _controller.MarkAsRead(999);

        // Assert
        var json = System.Text.Json.JsonSerializer.Serialize(result.Value);
        Assert.IsTrue(json.Contains("\"success\":true"));
    }

    #endregion

    #region Index Tests

    [TestMethod]
    public void Index_ReturnsView()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    #endregion
}

